int* findDuplicates(int* nums, int n, int* rs) {
    *rs=0; int cap=n; int* ans=malloc(cap*sizeof(int));
    for(int i=0;i<n;i++){
        int j=abs(nums[i])-1;
        if(nums[j]<0) ans[(*rs)++]=j+1;
        else nums[j]=-nums[j];
    }
    return ans;
}
